// 1. Extract the JSON string returned by BrowserAct
const raw = $json.output.string;

// 2. Parse it into a valid JavaScript object (array)
let products;
try {
  products = JSON.parse(raw);
} catch (e) {
  throw new Error("JSON parse failed: " + e.message);
}

// 3. Ensure the data is an array and convert it into n8n item format
if (!Array.isArray(products)) {
  throw new Error("Parsed data is not an array");
}

// 4. Return the result as iterable n8n items
return products.map(item => ({
  json: item
}));
